import React, { useState } from "react";
import "./ModelAccuracy.css";

function ModelAccuracy() {

  const data = {
    best_model: "XGBoost",
    best_accuracy: 93.4,
    all_models: {
      "Linear Regression": 82.5,
      "Random Forest": 91.2,
      "Decision Tree": 87.6,
      "XGBoost": 93.4
    }
  };

  const [show, setShow] = useState(false);

  return (
  <div className="container">

    {/* Card */}
    <div className="card" onClick={() => setShow(true)}>
      <h2 className="model">{data.best_model}</h2>
      <h1 className="acc">{data.best_accuracy}%</h1>
    </div>

    {/* Modal */}
    {show && (
      <div className="overlay">
        <div className="modal">
          <h2>Model Comparison</h2>

          {Object.entries(data.all_models).map(([model, acc]) => (
            <div className="row" key={model}>
              <span>{model}</span>
              <span>{acc}%</span>
            </div>
          ))}

          <button className="close-btn" onClick={() => setShow(false)}>
            Close
          </button>
        </div>
      </div>
    )}

  </div>
);
}

export default ModelAccuracy;
